@staticmethod
def _stock_hist_baostock(code: str, start_ymd: str, end_ymd: str, adjust: str = "qfq") -> pd.DataFrame:
    """Baostock fallback for stock history when akshare fails."""
    import baostock as bs
    bs.login()
    # Baostock adjustflag: 2=前复权, 1=后复权, 3=不复权
    adj_map = {"qfq": "2", "hfq": "1", "": "3", None: "3"}
    adj_flag = adj_map.get(adjust, "2")
    # Baostock prefix: sh. for 60xxxx, sz. for others
    prefix = "sh." if code.startswith("60") else "sz."
    rs = bs.query_history_k_data_plus(
        f"{prefix}{code}",
        "date,open,high,low,close,volume,amount",
        start_date=start_ymd, end_date=end_ymd,
        frequency="d", adjustflag=adj_flag
    )
    rows = []
    while rs.next():
        rows.append(rs.get_row_data())
    bs.logout()
    if not rows:
        return pd.DataFrame()
    df = pd.DataFrame(rows, columns=["date", "open", "high", "low", "close", "volume", "amount"])
    for col in ["open", "high", "low", "close", "volume", "amount"]:
        df[col] = pd.to_numeric(df[col], errors="coerce")
    return df

