def _require_tushare():
    try:
        import tushare as ts  # type: ignore
    except Exception as e:
        raise RuntimeError("tushare python package missing. Install 'tushare' to enable Tushare data source.") from e
    return ts


def _ts_pro(token: str):
    ts = _require_tushare()
    if not token:
        raise RuntimeError("TUSHARE_TOKEN missing. Set env var TUSHARE_TOKEN.")
    ts.set_token(token)
    return ts.pro_api()


def _safe_name(s: str) -> str:
    return "".join(ch if ch.isalnum() or ch in {"_", "-", "."} else "_" for ch in str(s))


def _norm_trade_date(ymd: str) -> str:
    s = str(ymd).strip().replace("-", "").replace("/", "")
    if len(s) == 8 and s.isdigit():
        return s
    raise ValueError(f"bad trade_date: {ymd}")


def _norm_ts_code(ts_code: str) -> str:
    return str(ts_code).strip().upper()


def _a_ts_code(code6: str) -> str:
    c = "".join(ch for ch in str(code6) if ch.isdigit()).zfill(6)
    if c.startswith(("60", "68", "5")):
        return f"{c}.SH"
    return f"{c}.SZ"


def _code6_from_ts(ts_code: str) -> str:
    s = _norm_ts_code(ts_code)
    if "." in s:
        s = s.split(".", 1)[0]
    digits = "".join(ch for ch in s if ch.isdigit())
    return digits.zfill(6) if digits else s


