def _baostock_industry_map(codes: list[str], asof_ymd: str, cache_dir: Path) -> dict[str, str]:
    cache_dir.mkdir(parents=True, exist_ok=True)
    cache_path = cache_dir / "industry_map.csv"

    existing: dict[str, str] = {}
    if cache_path.exists():
        try:
            df = pd.read_csv(cache_path)
            if set(df.columns) >= {"code", "industry"}:
                for r in df[["code", "industry"]].dropna().itertuples(index=False):
                    existing[str(getattr(r, "code")).zfill(6)] = str(getattr(r, "industry"))
        except Exception:
            existing = {}

    need = [str(c).zfill(6) for c in codes if str(c).zfill(6) not in existing]
    if not need:
        return existing

    y = str(asof_ymd).replace("-", "").replace("/", "")
    asof = f"{y[:4]}-{y[4:6]}-{y[6:8]}" if len(y) == 8 else str(asof_ymd)

    try:
        import baostock as bs

        lg = bs.login()
        if str(getattr(lg, "error_code", "")) != "0":
            return existing
        rows: list[dict[str, str]] = []
        for c in need:
            try:
                rs = bs.query_stock_industry(_baostock_code(c), asof)
                if rs is None:
                    continue
                while rs.next():
                    row = rs.get_row_data()
                    if not row or len(row) < 5:
                        continue
                    industry = str(row[3]).strip()
                    if industry:
                        existing[c] = industry
                        rows.append({"code": c, "industry": industry})
                        break
            except Exception:
                continue
        bs.logout()
        if rows:
            try:
                out = pd.DataFrame([{"code": k, "industry": v} for k, v in sorted(existing.items())])
                save_csv(out, cache_path)
            except Exception:
                pass
    except Exception:
        return existing

    return existing


def _round_price(x: float) -> float:
    return float(np.round(x + 1e-12, 2))


def _limit_up(prev_close: float) -> float:
    return _round_price(prev_close * 1.10)


def _limit_down(prev_close: float) -> float:
    return _round_price(prev_close * 0.90)


def _rsi(close: pd.Series, n: int = 14) -> pd.Series:
    delta = close.diff()
    up = delta.clip(lower=0.0)
    down = (-delta).clip(lower=0.0)
    roll_up = up.rolling(n).mean()
    roll_down = down.rolling(n).mean()
    rs = roll_up / roll_down.replace(0.0, np.nan)
    return 100.0 - (100.0 / (1.0 + rs))


def _to_close_series_any(df: pd.DataFrame) -> pd.Series:
    cols = {c: str(c).lower() for c in df.columns}
    close_col = next((c for c, lc in cols.items() if lc in {"close", "收盘"} or "收盘" in lc), None)
    if close_col is None:
        close_col = next((c for c, lc in cols.items() if "close" in lc), None)
    if close_col is None:
        raise RuntimeError("hist df missing close")
    return pd.to_numeric(df[close_col], errors="coerce").dropna()


