@dataclass(frozen=True)
class BaostockClient:
    @staticmethod
    def _prefix(code6: str) -> str:
        c = str(code6).strip().zfill(6)
        if c.startswith(("60", "68", "5")):
            return "sh."
        return "sz."

    @staticmethod
    def hist(symbol: str, start_ymd: str, end_ymd: str, adjust: str = "qfq") -> pd.DataFrame:
        import baostock as bs

        def _fmt(d: str) -> str:
            s = str(d).strip().replace("-", "").replace("/", "")
            if len(s) == 8 and s.isdigit():
                return f"{s[:4]}-{s[4:6]}-{s[6:8]}"
            return str(d).strip()

        adj_map = {"qfq": "2", "hfq": "1", "": "3", None: "3"}
        adj_flag = adj_map.get(adjust, "2")
        symbol = str(symbol).strip()

        lg = bs.login()
        if str(getattr(lg, "error_code", "")) != "0":
            return pd.DataFrame()

        rs = bs.query_history_k_data_plus(
            symbol,
            "date,open,high,low,close,volume,amount",
            start_date=_fmt(start_ymd),
            end_date=_fmt(end_ymd),
            frequency="d",
            adjustflag=adj_flag,
        )
        rows = []
        if rs is not None:
            while rs.next():
                rows.append(rs.get_row_data())
        bs.logout()
        if not rows:
            return pd.DataFrame()
        df = pd.DataFrame(rows, columns=["date", "open", "high", "low", "close", "volume", "amount"])
        for col in ["open", "high", "low", "close", "volume", "amount"]:
            df[col] = pd.to_numeric(df[col], errors="coerce")
        return df

    @staticmethod
    def stock_hist(code6: str, start_ymd: str, end_ymd: str, adjust: str = "qfq") -> pd.DataFrame:
        code = str(code6).strip().zfill(6)
        symbol = f"{BaostockClient._prefix(code)}{code}"
        return BaostockClient.hist(symbol=symbol, start_ymd=start_ymd, end_ymd=end_ymd, adjust=adjust)

    @staticmethod
    def stock_industry_map(codes: list[str], asof_ymd: str, cache_dir: Path) -> dict[str, str]:
        cache_dir.mkdir(parents=True, exist_ok=True)
        cache_path = cache_dir / "industry_map.csv"

        existing: dict[str, str] = {}
        cached = load_csv(cache_path)
        if isinstance(cached, pd.DataFrame) and not cached.empty and set(cached.columns) >= {"code", "industry"}:
            for r in cached[["code", "industry"]].dropna().itertuples(index=False):
                existing[str(getattr(r, "code")).zfill(6)] = str(getattr(r, "industry"))

        need = [str(c).zfill(6) for c in codes if str(c).zfill(6) not in existing]
        if not need:
            return existing

        y = str(asof_ymd).replace("-", "").replace("/", "")
        asof = f"{y[:4]}-{y[4:6]}-{y[6:8]}" if len(y) == 8 else str(asof_ymd)

