def _ts_pro(token: str):
    import os
    # Clash VPN 的系统代理会劫持 tushare 请求，强制忽略
    os.environ["NO_PROXY"] = "*"
    os.environ["no_proxy"] = "*"
    # Patch requests.Session.send 以跳过系统代理（最可靠的方式）
    import requests as _req
    _orig_send = _req.Session.send
    _patched = False
    def _no_proxy_send(self, request, **kwargs):
        if not _patched:
            self.trust_env = False
        return _orig_send(self, request, **kwargs)
    _req.Session.send = _no_proxy_send  # type: ignore[method-assign]

    ts = _require_tushare()
    if not token:
        raise RuntimeError("TUSHARE_TOKEN missing. Set env var TUSHARE_TOKEN.")
    ts.set_token(token)
    return ts.pro_api()

